fun solve(points: Array<Array<Long>>): Long {
    val MOD = 1000000007L
    val yMap = mutableMapOf<Long, Int>()
    for (point in points) {
        val y = point[1]
        yMap[y] = yMap.getOrDefault(y, 0) + 1
    }
    val counts = yMap.values.toList()
    var total = 0L
    for (i in 0 until counts.size) {
        for (j in i + 1 until counts.size) {
            val c1 = counts[i]
            val c2 = counts[j]
            val comb1 = (c1 * (c1 - 1)) / 2
            val comb2 = (c2 * (c2 - 1)) / 2
            total += comb1 * comb2
            total %= MOD
        }
    }
    return total
}
